// PATCH /api/documents/:id - Update a document
router.patch('/api/documents/:id', requireAuth, async (req, res) => {
  try {
    const documentId = req.params.id;
    
    const existingDoc = await db.query(
      'SELECT id, created_by FROM documents WHERE id = $1 AND company_id = $2',
      [documentId, req.user.companyId]
    );
    
    if (existingDoc.rows.length === 0) {
      return res.status(404).json({ error: 'Document not found' });
    }
    
    const allowedFields = ['title', 'content'];
    const updates = {};
    
    if (req.body.title !== undefined) {
      if (typeof req.body.title !== 'string' || req.body.title.trim().length === 0) {
        return res.status(400).json({ error: 'Invalid title' });
      }
      updates.title = req.body.title.trim();
    }
    
    if (req.body.content !== undefined) {
      if (typeof req.body.content !== 'string') {
        return res.status(400).json({ error: 'Invalid content' });
      }
      updates.content = req.body.content;
    }
    
    if (Object.keys(updates).length === 0) {
      return res.status(400).json({ error: 'No valid fields to update' });
    }
    
    const setClauses = [];
    const values = [];
    let paramIndex = 1;
    
    if (updates.title !== undefined) {
      setClauses.push(`title = $${paramIndex++}`);
      values.push(updates.title);
    }
    
    if (updates.content !== undefined) {
      setClauses.push(`content = $${paramIndex++}`);
      values.push(updates.content);
    }
    
    setClauses.push(`updated_at = CURRENT_TIMESTAMP`);
    values.push(documentId, req.user.companyId);
    
    const result = await db.query(
      `UPDATE documents SET ${setClauses.join(', ')} WHERE id = $${paramIndex} AND company_id = $${paramIndex + 1} RETURNING id, title, content, created_at, updated_at, created_by`,
      values
    );
    
    res.json({ document: result.rows[0] });
  } catch (error) {
    console.error('Error updating document:', error);
    res.status(500).json({ error: 'Internal server error' });
  }
});

